import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Api from "../api/Api";

function Admin() {
const [users, setUsers] = useState([]);
const [scheduleMap, setScheduleMap] = useState({});
const [editingSchedule, setEditingSchedule] = useState({});
const [showRequests, setShowRequests] = useState(false);
const [requests, setRequests] = useState([]);
const [orderMap, setOrderMap] = useState({});
const [isSorted, setIsSorted] = useState(false);
  // ================= USERS =================
  const fetchUsers = async () => {
    try {
      const res = await axios.get(Api.get_All_User);
      setUsers(res.data || []);
    } catch (err) {
      console.log(err);
    }
  };

  // ================= REQUESTS =================
  const fetchRequests = async () => {
    try {
      const res = await axios.get(Api.get_All_Emg_Req);

      console.log("RAW RESPONSE:", res.data);

      const data =
        res.data?.data ||
        res.data?.requests ||
        res.data ||
        [];

      setRequests(Array.isArray(data) ? data : []);
    } catch (err) {
      console.log("FETCH ERROR:", err);
      setRequests([]);
    }
  };
  useEffect(() => {
    fetchUsers();
  }, []);

  // ================= ASSIGN ORDER (LIVE UI UPDATE) =================
  const handleAssignOrder = async (id) => {
    try {
      const order = orderMap[id];

      if (order === undefined || order === "") {
        return alert("Enter order first");
      }

      const numOrder = Number(order);

      // 🔥 UI UPDATE FIRST
      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? { ...req, scheduleOrder: numOrder }
            : req
        )
      );

      // 🔥 API CALL (CORRECT)
      const res = await axios.put(
        `${Api.update_Emg_Order}/${id}`,
        {
          scheduleOrder: numOrder,
        }
      );

      console.log("UPDATE RESPONSE:", res.data);

      setOrderMap({});
      setIsSorted(false);

    } catch (err) {
      console.log("ASSIGN ERROR:", err.response || err);
      alert("Assign failed");
    }
  };

  // ================= UPDATE ORDER =================
  const handleUpdateAssign = async (id) => {
    try {
      const order = orderMap[id];

      if (!order && order !== 0) {
        return alert("Enter order first");
      }

      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? { ...req, scheduleOrder: Number(order) }
            : req
        )
      );

      await axios.put(
        `${Api.update_Emg_Order}/${id}`,
        {
          scheduleOrder: Number(order),
        }
      );

      setOrderMap({});
      setIsSorted(false);

    } catch (err) {
      console.log(err);
    }
  };

  // ================= FINAL SORT =================
  const displayedRequests = isSorted
    ? [...requests].sort((a, b) => {
      return (a.scheduleOrder || 0) - (b.scheduleOrder || 0);
    })
    : requests;




const handleSchedule = async (id) => {
  try {
    const data = scheduleMap[id];

    if (!data?.date || !data?.time) {
      return alert("Select Date & Time");
    }

    await axios.put(`${Api.update_Emg_Order}/${id}`, {
      scheduledDate: data.date,
      scheduledTime: data.time,
      status: "Assigned",
    });

    setRequests((prev) =>
      prev.map((req) =>
        req._id === id
          ? {
              ...req,
              scheduledDate: data.date,
              scheduledTime: data.time,
              status: "Assigned",
            }
          : req
      )
    );

    setEditingSchedule((prev) => ({
      ...prev,
      [id]: false,
    }));

    setScheduleMap((prev) => ({
      ...prev,
      [id]: {},
    }));

    alert("Schedule Updated Successfully");
  } catch (error) {
    console.log(error);
    alert("Schedule Failed");
  }
};


  return (
    <div className="min-h-screen bg-[#4CBB17]/20">

      <div >

        {/* HEADER */}
        {/* HEADER */}
   <div className="mb-8 bg-[#4CBB17]/40 px-6 ">
  <div className="flex items-center justify-between">
    
    {/* Logo + Title */}
    <div >
      <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
        <img
          src="garbageVehicle.jpeg"
          alt=""
          className="w-16 h-16 object-contain"
        />
        CleanTrack
      </h1>

      <p className="text-gray-900 p-2">
        Smart Waste Management Control Center
      </p>
    </div>

    {/* Navigation Links */}
    <div className="flex items-center gap-8 text-lg font-semibold">
      
      <Link
        to="/send-otp"
        className="text-green-900 hover:text-white-900 transition-all duration-300 hover:scale-105"
      >
        Create User
      </Link>

      <button
        onClick={() => {
          setShowRequests(!showRequests);
          fetchRequests();
        }}
        className="text-green-900 hover:text-green-900 transition-all duration-300 hover:scale-105"
      >
        View Requests
      </button>

    </div>
  </div>
</div>

        {/* USERS */}
        <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-6 mb-8 m-8">

          <div className="flex justify-between items-center mb-6">

            <h2 className="text-2xl font-bold text-green-900">
              User Management
            </h2>

            <span className="bg-green-100 text-green-800 px-4 py-2 rounded-full text-sm font-semibold">
              {users.length} Users
            </span>

          </div>

          <div className="overflow-x-auto">

            <table className="w-full">

              <thead>
                <tr className="bg-green-900 text-white">
                  <th className="p-4 text-left">Name</th>
                  <th className="p-4 text-left">Mobile</th>
                  <th className="p-4 text-left">Role</th>
                </tr>
              </thead>

              <tbody>
                {users.map((user) => (
                  <tr
                    key={user._id}
                    className="border-b hover:bg-green-50 transition"
                  >
                    <td className="p-4 font-medium">
                      {user.name}
                    </td>

                    <td className="p-4">
                      {user.mobile}
                    </td>

                    <td className="p-4">
                      <span className="bg-green-100 text-green-800 px-3 py-1 rounded-full text-sm font-medium">
                        {user.role}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>

            </table>

          </div>

        </div>

        {/* REQUESTS */}
        {showRequests && (
          <div>

            <div className="flex justify-between items-center mb-6 m-8">

              <div>
                <h2 className="text-3xl font-bold text-green-900">
                  Active Requests
                </h2>

                <p className="text-gray-500 text-sm">
                  Pickup Scheduling & Monitoring
                </p>
              </div>

              <div className="bg-white border border-[#d6ddd2] px-5 py-3 rounded-xl">
                <span className="font-semibold">
                  Total Requests:
                </span>{" "}
                {displayedRequests.length}
              </div>

            </div>

            {displayedRequests.length === 0 ? (

              <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-10 text-center">
                No requests found
              </div>

            ) : (

              <div className="grid lg:grid-cols-2 xl:grid-cols-4 gap-6">

                {displayedRequests.map((req) => (

                  <div
                    key={req._id}
                    className="bg-white rounded-2xl border border-[#d6ddd2] p-6 hover:shadow-lg transition m-8"
                  >

                    {/* TOP */}
                    <div className="flex justify-between items-start">

                      <div>

                        <p className="text-xs uppercase tracking-wider text-gray-500">
                          Request #{req._id.slice(-5)}
                        </p>

                        <h3 className="text-xl font-bold text-green-900 mt-1">
                          {req.location?.location}
                        </h3>

                      </div>

                      <span
                        className={`px-4 py-1 rounded-full text-sm font-semibold
                      ${req.status === "Completed"
  ? "bg-blue-800 text-blue-700"
  : req.status === "schedule"
  ? "bg-purple-100 text-purple-700"
  : req.status === "Pending"
  ? "bg-yellow-100 text-yellow-700"
  : "bg-gray-100 text-gray-700"
}`}
                      >
                        {req.status}
                      </span>

                    </div>

                    {/* INFO */}
                    <div className="mt-5 space-y-2">

                      <p>
                        <span className="font-semibold">
                          Priority:
                        </span>{" "}
                        {req.priority}
                      </p>

                      <p className="text-sm text-gray-500 mt-4">Created:
                        {new Date(req.createdAt).toLocaleString("en-IN", {
                          day: "2-digit",
                          month: "short",
                          year: "numeric",
                          hour: "2-digit",
                          minute: "2-digit",
                          hour12: true,
                        })}
                      </p>



                    </div>

{/* SCHEDULE SECTION */}

<div className="mt-5 border-t pt-4">

  {req.scheduledDate && !editingSchedule[req._id] ? (

    <>
      <div className="bg-green-50 border border-green-200 rounded-xl p-4">

        <h4 className="font-bold text-green-900 mb-3">
          Scheduled Pickup
        </h4>

     <p className="text-sm">
  <span className="font-semibold">Date:</span>{" "}
  {new Date(req.scheduledDate).toLocaleDateString("en-IN")}
</p>

       <p className="text-sm mt-2">
   <span className="font-semibold">Time:</span>{" "}
  {req.scheduledTime}
</p>

      </div>

      <button
        onClick={() =>
          setEditingSchedule((prev) => ({
            ...prev,
            [req._id]: true,
          }))
        }
        className="mt-3 w-full bg-yellow-500 hover:bg-yellow-600 text-white py-2 rounded-xl font-semibold transition"
      >
        Update Schedule
      </button>
    </>

  ) : (

    <>
      <h4 className="font-bold text-green-900 mb-3">
        Schedule Pickup
      </h4>

      <div className="space-y-3">

        <input
          type="date"
          className="w-full border border-gray-300 rounded-lg p-2"
          value={scheduleMap[req._id]?.date || ""}
          onChange={(e) =>
            setScheduleMap((prev) => ({
              ...prev,
              [req._id]: {
                ...prev[req._id],
                date: e.target.value,
              },
            }))
          }
        />

        <input
          type="time"
          className="w-full border border-gray-300 rounded-lg p-2"
          value={scheduleMap[req._id]?.time || ""}
          onChange={(e) =>
            setScheduleMap((prev) => ({
              ...prev,
              [req._id]: {
                ...prev[req._id],
                time: e.target.value,
              },
            }))
          }
        />

        <button
          onClick={() => handleSchedule(req._id)}
          className="w-full bg-green-900 hover:bg-green-800 text-white py-2 rounded-xl font-semibold transition"
        >
          {req.scheduledDate ? "Save Update" : "Schedule"}
        </button>

      </div>
    </>

  )}

</div>



                  </div>

                ))}

              </div>

            )}

          </div>
        )}

      </div>

    </div>
  );
}

export default Admin;
